SELECT COUNT(production_order_id) AS completed_orders_count
FROM production_orders
WHERE status = 'Completed';

SELECT article_name, status
FROM production_orders
ORDER BY status;

SELECT SUM(p.quantity) AS total_quantity
FROM production_orders p
WHERE p.status = 'Completed' AND p.customer_id = 1;

SELECT SUM(duration) AS total_downtime_duration
FROM equipment_status
WHERE type = 'DownTime';

SELECT SUM(duration) AS total_downtime
FROM equipment_status
WHERE equipment_id = 1 AND type = 'DownTime';
